INSERT INTO TB_FILE_DTL (
	file_seq,
	file_nm,
	file_path,
	file_type,
	del_yn,
	srt_sq,
	rgst_user_id,
	rgst_date_time,
	upt_user_id,
	upt_date_time
) VALUES(
	#{fileSeq}
	,#{fileNm}
	,#{filePath}
	,#{fileType}
	,'N'
	,#{srtSq}
	,#{rgstUserId}
	,NOW()
	,#{uptUserId}
	,NOW()
)

